unsafe_example:
// UNSAFE: user input becomes the command
string cmd = Request.Query["cmd"];
Process.Start(cmd);

// UNSAFE: shell invocation via FileName + Arguments concat
var psi = new ProcessStartInfo("cmd.exe", "/c " + userInput);
Process.Start(psi);

safe_example:
// SAFE: explicit argument list, no shell, allowlist check
string name = Request.Query["name"];
if (!AllowedNames.Contains(name))
    throw new SecurityException("disallowed name");

var psi = new ProcessStartInfo("/usr/bin/mytool")
{
    UseShellExecute = false,
    RedirectStandardOutput = true
};
psi.ArgumentList.Add("--name");
psi.ArgumentList.Add(name);
var proc = Process.Start(psi);
